import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loginAdmin, registerAdmin } from "../services/api";
import "../css/Login.css";

function Login() {
  const navigate = useNavigate();
  const [mode, setMode] = useState("login");
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    password: "",
  });
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("danger");

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");

    try {
      const response =
        mode === "login"
          ? await loginAdmin({ email: formData.email, password: formData.password })
          : await registerAdmin(formData);

      localStorage.setItem("kirana_token", response.data.token);
      localStorage.setItem("kirana_admin", JSON.stringify(response.data.admin));
      navigate("/");
    } catch (error) {
      setMessageType("danger");
      setMessage(error.response?.data?.message || "Authentication failed.");
    }
  };

  return (
    <section className="login-page">
      <div className="login-card card border-0 shadow">
        <div className="card-body">
          <h2 className="login-title">Kirana CRM</h2>
          <p className="login-subtitle">
            {mode === "login"
              ? "Owner login to manage your kirana store"
              : "Create your owner account"}
          </p>
          {message ? <div className={`alert alert-${messageType}`}>{message}</div> : null}
          <form onSubmit={handleSubmit}>
            {mode === "register" ? (
              <div className="mb-3">
                <label htmlFor="name" className="form-label">
                  Name
                </label>
                <input
                  id="name"
                  name="name"
                  type="text"
                  className="form-control"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>
            ) : null}
            <div className="mb-3">
              <label htmlFor="email" className="form-label">
                Email
              </label>
              <input
                id="email"
                name="email"
                type="email"
                className="form-control"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="mb-3">
              <label htmlFor="password" className="form-label">
                Password
              </label>
              <input
                id="password"
                name="password"
                type="password"
                className="form-control"
                value={formData.password}
                onChange={handleChange}
                required
              />
            </div>
            <button type="submit" className="btn login-btn w-100">
              {mode === "login" ? "Login" : "Register"}
            </button>
          </form>

          <button
            type="button"
            className="btn btn-link switch-auth-btn"
            onClick={() => setMode((prev) => (prev === "login" ? "register" : "login"))}
          >
            {mode === "login" ? "First-time owner setup? Register" : "Already have owner account? Login"}
          </button>
        </div>
      </div>
    </section>
  );
}

export default Login;
